impl Drop for TextureSet {
    fn drop(&mut self) {
        unsafe {
            for &tex in &self.textures { let _ = sys::lib().cuTexObjectDestroy(tex); }
            for &arr in &self.arrays   { let _ = sys::lib().cuArrayDestroy(arr); }
        }
    }
